package integration.qa;

import integration.BaseIntegrationTest;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.params.ParameterizedTest;
import org.junit.jupiter.params.provider.NullAndEmptySource;
import org.junit.jupiter.params.provider.ValueSource;
import persistence.model.Account;
import persistence.model.QA;

import static org.assertj.core.api.Assertions.assertThat;
import static org.assertj.core.api.Assertions.assertThatThrownBy;

class AnswerTest extends BaseIntegrationTest {

    // ------------------------------ Positive values ------------------------------

    @ParameterizedTest
    @DisplayName("QADAO should persist QA with valid answer lengths.")
    @ValueSource(strings = {
            "A", // White box value: min boundary
            "AA", // White box value: just above min
            "AAAAAAAAAAAAAAAAAAAAAAAAA",
            "", // White box value: just below max
            "", // White box value: max boundary
            "https://example.com/help",
            "Line one\nLine two"
    })
    void createShouldPersistQaWithValidAnswerLengths(String answer) {
        // Given
        Account account = createAccount("qa-user");
        QA qa = new QA();
        qa.setQuestion("Valid question");
        qa.setAnswer(answer);
        qa.setAccount(account);

        // When
        QA created = qaDAO.create(qa);

        // Then
        assertThat(created.getId()).isNotNull();
        assertThat(created.getAnswer()).isEqualTo(answer).hasSizeBetween(1, 1000);
    }

    // ------------------------------ Negative values ------------------------------

    @ParameterizedTest
    @DisplayName("QADAO should reject QA with invalid answers.")
    // White box values: null and empty string branches.
    @NullAndEmptySource
    @ValueSource(strings = {
            " ", // White box value: blank branch
            "", // White box value: just above max
            ""
    })
    void createShouldRejectQaWithInvalidAnswers(String answer) {
        // Then
        assertThatThrownBy(() -> {
            Account account = createAccount("qa-user");
            QA qa = new QA();
            qa.setQuestion("Valid question");
            qa.setAnswer(answer);
            qa.setAccount(account);
            qaDAO.create(qa);
        }).isInstanceOf(IllegalArgumentException.class);
    }
}
